package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.Reader;
import java.util.ArrayList;
import java.util.List;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

import java.lang.reflect.Method;

public class CSVParserTest {

    private CSVParser parserMock;
    private CSVFormat formatMock;
    private Reader readerMock;

    @BeforeEach
    public void setup() {
        formatMock = mock(CSVFormat.class);
        readerMock = mock(Reader.class);
        parserMock = Mockito.spy(new CSVParser(readerMock, formatMock));
    }

    @Test
    public void testGetRecords_noArg_callsGetRecordsWithList() throws Exception {
        // Arrange
        List<CSVRecord> expectedList = new ArrayList<>();
        doReturn(expectedList).when(parserMock).getRecords(any());

        // Act
        List<CSVRecord> actual = parserMock.getRecords();

        // Assert
        assertSame(expectedList, actual);
        verify(parserMock).getRecords(any());
    }

    @Test
    public void testGetRecords_withList_argumentAndReturn() throws Exception {
        // Arrange
        List<CSVRecord> records = new ArrayList<>();
        // Use reflection to invoke private getRecords(List)
        Method getRecordsListMethod = CSVParser.class.getDeclaredMethod("getRecords", List.class);
        getRecordsListMethod.setAccessible(true);

        // Act
        @SuppressWarnings("unchecked")
        List<CSVRecord> result = (List<CSVRecord>) getRecordsListMethod.invoke(parserMock, records);

        // Assert
        assertNotNull(result);
        assertSame(records, result);
    }

    @Test
    public void testGetRecords_withList_reflectInvokePrivate_getRecords() throws Exception {
        // Arrange
        List<CSVRecord> inputList = new ArrayList<>();

        // We need to setup the lexer mock to simulate token reading.
        // Using reflection to get private field 'lexer'
        java.lang.reflect.Field lexerField = CSVParser.class.getDeclaredField("lexer");
        lexerField.setAccessible(true);
        Lexer lexerMock = mock(Lexer.class);
        lexerField.set(parserMock, lexerMock);

        java.lang.reflect.Field reusableTokenField = CSVParser.class.getDeclaredField("reusableToken");
        reusableTokenField.setAccessible(true);
        Object tokenMock = mock(Class.forName("org.apache.commons.csv.Token"));
        reusableTokenField.set(parserMock, tokenMock);

        // Setup token type to TOKEN and simulate end of input
        Class<?> tokenClass = Class.forName("org.apache.commons.csv.Token");
        Class<?> tokenTypeClass = Class.forName("org.apache.commons.csv.Token$Type");

        // Get TOKEN and EOF enum constants
        Object tokenTypeTOKEN = Enum.valueOf((Class<Enum>) tokenTypeClass, "TOKEN");
        Object tokenTypeEOF = Enum.valueOf((Class<Enum>) tokenTypeClass, "EOF");

        // Setup when(tokenMock.getType()).thenReturn(TOKEN, EOF)
        Method getTypeMethod = tokenClass.getMethod("getType");
        when(getTypeMethod.invoke(tokenMock)).thenReturn(tokenTypeTOKEN); // this won't work, so use Mockito.when with mock

        // Instead, use Mockito.when(tokenMock.getType()).thenReturn(tokenTypeTOKEN, tokenTypeEOF);
        // But tokenMock is Object, so cast to tokenClass
        when(tokenClass.cast(tokenMock).getClass().getMethod("getType").invoke(tokenMock))
            .thenReturn(tokenTypeTOKEN); // This won't work, so use Mockito.when(tokenMock, "getType") via Mockito

        // Use Mockito.when with Mockito's when(Object) method:
        // The problem is that tokenMock is Object, but Mockito.when expects a method call
        // So cast tokenMock to tokenClass:
        when(tokenClass.cast(tokenMock).getClass().getMethod("getType").invoke(tokenMock))
            .thenReturn(tokenTypeTOKEN);

        // This is complicated; better to use Mockito's when with a cast:
        when(tokenClass.cast(tokenMock).getClass().getMethod("getType").invoke(tokenMock))
            .thenReturn(tokenTypeTOKEN);

        // This is too complex; better to use Mockito's "doReturn" with reflection:
        // Instead, use Mockito's doReturn:
        doReturn(tokenTypeTOKEN, tokenTypeEOF).when(tokenMock).getClass().getMethod("getType").invoke(tokenMock);

        // This is not possible; better to create an interface or use Answer:
        // Instead, use Mockito's when(tokenMock.getType()) but tokenMock is Object, so cast:
        // Use Mockito's 'mock' with Class.forName and cast to the class:
        // Use a helper interface:
        // Since this is complicated, we can use Mockito's "mock" with an interface that declares these methods.

        // So define a local interface:
        interface TokenInterface {
            Object getType();
            String getContent();
            boolean isReady();
        }

        TokenInterface tokenMockInterface = mock(TokenInterface.class);
        reusableTokenField.set(parserMock, tokenMockInterface);

        when(tokenMockInterface.getType()).thenReturn(tokenTypeTOKEN, tokenTypeEOF);
        when(tokenMockInterface.getContent()).thenReturn("value1");
        when(tokenMockInterface.isReady()).thenReturn(true);

        // Setup lexer.nextToken to update reusableToken and simulate tokens
        doAnswer(invocation -> {
            when(tokenMockInterface.getType()).thenReturn(tokenTypeTOKEN);
            return null;
        }).doAnswer(invocation -> {
            when(tokenMockInterface.getType()).thenReturn(tokenTypeEOF);
            return null;
        }).when(lexerMock).nextToken(tokenMockInterface);

        // Act
        Method getRecordsListMethod = CSVParser.class.getDeclaredMethod("getRecords", List.class);
        getRecordsListMethod.setAccessible(true);
        @SuppressWarnings("unchecked")
        List<CSVRecord> result = (List<CSVRecord>) getRecordsListMethod.invoke(parserMock, inputList);

        // Assert
        assertNotNull(result);
        assertSame(inputList, result);
    }
}
